/*
 * F14 fixture: small C program with NO csrwi 0x7C0,* trigger anywhere.
 * Exits naturally via crt0 -> _exit (libgloss_vh semihosting EXIT).
 *
 * QEMU sees the semihosting EXIT and runs its atexit chain; the
 * hybrid_handoff plugin's `drain_at_exit=1` callback drains state and
 * _exit(200) so ./hsim estimate --icount 0 can read minstret as N_total.
 *
 * Loop is sized so the BBV profile pass at slice=1000 produces enough
 * rows for SimPoint --max-k 2 (>= 2 rows; we want >= 10 for safety).
 */
#include <stdio.h>

int main(void) {
    long acc = 0;
    for (long i = 0; i < 2000; i++) {
        acc += i * 3 + 7;
    }
    printf("no_trigger_exit acc=%ld\n", acc);
    return 0;
}
---
==> hello.c <==
int int main(int argc, char *argv[])
{
 printf("Hello\n") ;
  return 0;
}

==> gemm.c <==
#include <stdio.h>

#define N 32

static float A[N][N];
static float B[N][N];
static float C[N][N];

static void init(void) {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            A[i][j] = (float)(i + j);
            B[i][j] = (float)(i - j);
            C[i][j] = 0.0f;
        }
    }
}

static void gemm(void) {
    for (int i = 0; i < N; i++) {
        for (int k = 0; k < N; k++) {
            float a = A[i][k];
            for (int j = 0; j < N; j++) {
                C[i][j] += a * B[k][j];
            }
        }
    }
}

int main(void) {
    init();
    gemm();
    printf("C[0][0]=%f C[N-1][N-1]=%f\n", C[0][0], C[N-1][N-1]);
    return 0;
}

